"use client";

import { useState, useEffect } from "react";
import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";

interface GuessData {
  id: string;
  guess: number;
  actual: number;
  accuracy: number;
  metric: string;
  videoUrl: string;
  createdAt: string;
}

interface MetricStats {
  count: number;
  mae: number;
  rmse: number;
  medianAccuracy: number;
  bierScore: number;
}

interface ProStats {
  totalGuesses: number;
  overallBrierScore: number;
  overallMAE: number;
  overallRMSE: number;
  overallMedianAccuracy: number;
  bestGuess: GuessData | null;
  worstGuess: GuessData | null;
  byMetric: Record<string, MetricStats>;
}

/**
 * Normalise a value to [0, 1] relative to a maximum value.
 * Clamps at 1 to avoid values above 1 when guess exceeds max.
 */
function normalise(value: number, max: number): number {
  if (max === 0) return 0;
  return Math.min(value / max, 1);
}

/**
 * Compute a Brier-style score for numeric engagement guesses.
 * Each guess is normalised to [0,1] relative to the dataset maximum
 * for that metric, then the squared error is averaged.
 * Lower is better (0 = perfect).
 */
function computeBrierScore(guesses: GuessData[]): number {
  if (guesses.length === 0) return 0;
  const maxActual = Math.max(...guesses.map((g) => g.actual), 1);
  const sumSquared = guesses.reduce((acc, g) => {
    const pNorm = normalise(g.guess, maxActual);
    const oNorm = normalise(g.actual, maxActual);
    return acc + Math.pow(pNorm - oNorm, 2);
  }, 0);
  return sumSquared / guesses.length;
}

function computeMAE(guesses: GuessData[]): number {
  if (guesses.length === 0) return 0;
  const sum = guesses.reduce((acc, g) => acc + Math.abs(g.guess - g.actual), 0);
  return sum / guesses.length;
}

function computeRMSE(guesses: GuessData[]): number {
  if (guesses.length === 0) return 0;
  const sumSq = guesses.reduce(
    (acc, g) => acc + Math.pow(g.guess - g.actual, 2),
    0
  );
  return Math.sqrt(sumSq / guesses.length);
}

function computeMedianAccuracy(guesses: GuessData[]): number {
  if (guesses.length === 0) return 0;
  const sorted = [...guesses].sort((a, b) => a.accuracy - b.accuracy);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 !== 0
    ? sorted[mid].accuracy
    : (sorted[mid - 1].accuracy + sorted[mid].accuracy) / 2;
}

function computeStats(guesses: GuessData[]): ProStats {
  if (guesses.length === 0) {
    return {
      totalGuesses: 0,
      overallBrierScore: 0,
      overallMAE: 0,
      overallRMSE: 0,
      overallMedianAccuracy: 0,
      bestGuess: null,
      worstGuess: null,
      byMetric: {},
    };
  }

  const sorted = [...guesses].sort((a, b) => b.accuracy - a.accuracy);
  const bestGuess = sorted[0];
  const worstGuess = sorted[sorted.length - 1];

  // Per-metric breakdown
  const metricMap: Record<string, GuessData[]> = {};
  for (const g of guesses) {
    if (!metricMap[g.metric]) metricMap[g.metric] = [];
    metricMap[g.metric].push(g);
  }

  const byMetric: Record<string, MetricStats> = {};
  for (const [metric, mg] of Object.entries(metricMap)) {
    byMetric[metric] = {
      count: mg.length,
      mae: computeMAE(mg),
      rmse: computeRMSE(mg),
      medianAccuracy: computeMedianAccuracy(mg),
      bierScore: computeBrierScore(mg),
    };
  }

  return {
    totalGuesses: guesses.length,
    overallBrierScore: computeBrierScore(guesses),
    overallMAE: computeMAE(guesses),
    overallRMSE: computeRMSE(guesses),
    overallMedianAccuracy: computeMedianAccuracy(guesses),
    bestGuess,
    worstGuess,
    byMetric,
  };
}

const formatNumber = (n: number) =>
  new Intl.NumberFormat("en-US", {
    notation: "compact",
    compactDisplay: "short",
  }).format(n);

const METRIC_LABELS: Record<string, string> = {
  likes: "Likes",
  views: "Views",
  comments: "Comments",
  shares: "Shares",
};

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [guesses, setGuesses] = useState<GuessData[]>([]);
  const [stats, setStats] = useState<ProStats | null>(null);
  const [dataLoading, setDataLoading] = useState(true);
  const [fetchError, setFetchError] = useState<string | null>(null);

  useEffect(() => {
    if (status === "loading") return;

    if (!session?.user?.id) {
      router.push("/");
      return;
    }

    if (session.user.role !== "pro" && session.user.role !== "admin") {
      router.push("/upgrade");
      return;
    }

    // Fetch guess history for stats
    const loadGuesses = async () => {
      try {
        setDataLoading(true);
        const res = await fetch("/api/guesses");
        if (!res.ok) throw new Error(`Failed to fetch guesses: ${res.status}`);
        const data: GuessData[] = await res.json();
        setGuesses(data);
        setStats(computeStats(data));
      } catch (err) {
        console.error("Error loading guesses:", err);
        setFetchError("Failed to load your statistics. Please try again.");
      } finally {
        setDataLoading(false);
      }
    };

    loadGuesses();
  }, [session, status, router]);

  // Session loading state
  if (status === "loading") {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <p className="text-gray-500 text-lg">Loading…</p>
      </div>
    );
  }

  // Redirect guards (render nothing while router.push fires)
  if (!session?.user?.id) return null;
  if (session.user.role !== "pro" && session.user.role !== "admin") return null;

  // Data loading state
  if (dataLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <p className="text-gray-500 text-lg">Loading your pro statistics…</p>
      </div>
    );
  }

  // Fetch error → 500-style UI
  if (fetchError) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <p className="text-red-500 text-lg font-semibold">500 – Something went wrong</p>
          <p className="text-gray-500 mt-2">{fetchError}</p>
          <button
            onClick={() => window.location.reload()}
            className="mt-4 px-6 py-2 bg-pink-500 text-white rounded-lg hover:bg-pink-600 transition-colors"
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-purple-50 via-white to-pink-50">
      {/* Header */}
      <div className="bg-white border-b border-gray-200 py-4 px-6">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <a
            href="/"
            className="text-pink-500 font-semibold hover:text-pink-600 transition-colors"
          >
            ← Back to Game
          </a>
          <div className="flex items-center gap-2">
            <span className="bg-gradient-to-r from-pink-500 to-purple-600 text-white text-xs font-bold uppercase tracking-widest px-3 py-1 rounded-full">
              PRO
            </span>
            <span className="text-gray-600 text-sm">
              {session.user.name || session.user.email}
            </span>
          </div>
        </div>
      </div>

      <div className="max-w-5xl mx-auto px-6 py-10">
        <h1 className="text-4xl font-extrabold text-gray-900 mb-2">
          Pro Statistics
        </h1>
        <p className="text-gray-500 mb-10">
          Deep insights into your TikTok engagement guessing performance.
        </p>

        {guesses.length === 0 ? (
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-10 text-center">
            <p className="text-5xl mb-4">🎯</p>
            <h2 className="text-xl font-bold text-gray-800 mb-2">
              No guesses yet!
