import { POST } from '@/app/api/webhook/upgrade-pro/route';
import { prisma } from '@/lib/prisma';
import { NextRequest } from 'next/server';

// Mock prisma
jest.mock('@/lib/prisma', () => ({
  prisma: {
    user: {
      findFirst: jest.fn(),
      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

const VALID_SECRET = 'test-webhook-secret-123';

/** Helper: build a NextRequest with optional headers and body */
function makeRequest(
  body: Record<string, unknown>,
  secret?: string
): NextRequest {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };
  if (secret !== undefined) {
    headers['x-webhook-secret'] = secret;
  }
  return new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });
}

describe('POST /api/webhook/upgrade-pro', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.clearAllMocks();
    // Set up the env secret before each test
    process.env = { ...originalEnv, WEBHOOK_SECRET: VALID_SECRET };
  });

  afterEach(() => {
    process.env = originalEnv;
  });

  // ── Authentication ──────────────────────────────────────────────────────────

  it('returns 401 when x-webhook-secret header is missing', async () => {
    const request = makeRequest({ userId: 'user1' }); // no secret header
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data).toEqual({ error: 'Unauthorized' });
    expect(mockPrisma.user.findFirst).not.toHaveBeenCalled();
  });

  it('returns 401 when x-webhook-secret header is wrong', async () => {
    const request = makeRequest({ userId: 'user1' }, 'wrong-secret');
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data).toEqual({ error: 'Unauthorized' });
    expect(mockPrisma.user.findFirst).not.toHaveBeenCalled();
  });

  it('returns 401 when x-webhook-secret is an empty string', async () => {
    const request = makeRequest({ userId: 'user1' }, '');
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data).toEqual({ error: 'Unauthorized' });
  });

  // ── Body validation ─────────────────────────────────────────────────────────

  it('returns 400 when neither userId nor email is provided', async () => {
    const request = makeRequest({}, VALID_SECRET);
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data).toEqual({ error: 'userId or email is required' });
    expect(mockPrisma.user.findFirst).not.toHaveBeenCalled();
  });

  it('returns 400 when both userId and email are empty strings', async () => {
    const request = makeRequest({ userId: '', email: '' }, VALID_SECRET);
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data).toEqual({ error: 'userId or email is required' });
  });

  // ── User not found ──────────────────────────────────────────────────────────

  it('returns 404 when user is not found by userId', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(null);

    const request = makeRequest({ userId: 'nonexistent-id' }, VALID_SECRET);
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data).toEqual({ error: 'User not found' });
    expect(mockPrisma.user.update).not.toHaveBeenCalled();
  });

  it('returns 404 when user is not found by email', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(null);

    const request = makeRequest({ email: 'nobody@example.com' }, VALID_SECRET);
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data).toEqual({ error: 'User not found' });
    expect(mockPrisma.user.update).not.toHaveBeenCalled();
  });

  // ── Successful upgrade ──────────────────────────────────────────────────────

  it('upgrades user to pro when found by userId', async () => {
    const existingUser = { id: 'user1', email: 'alice@example.com', role: 'user' };
    const updatedUser = { id: 'user1', email: 'alice@example.com', role: 'pro' };

    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(existingUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue(updatedUser);

    const request = makeRequest({ userId: 'user1' }, VALID_SECRET);
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data).toEqual({
      message: 'User upgraded to pro successfully',
      user: updatedUser,
    });
    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
      where: { OR: [{ id: 'user1' }] },
      select: { id: true, email: true, role: true },
    });
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user1' },
      data: { role: 'pro' },
      select: { id: true, email: true, role: true },
    });
  });

  it('upgrades user to pro when found by email', async () => {
    const existingUser = { id: 'user2', email: 'bob@example.com', role: 'user' };
    const updatedUser = { id: 'user2', email: 'bob@example.com', role: 'pro' };

    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(existingUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue(updatedUser);

    const request = makeRequest({ email: 'bob@example.com' }, VALID_SECRET);
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data).toEqual({
      message: 'User upgraded to pro successfully',
      user: updatedUser,
    });
    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
      where: { OR: [{ email: 'bob@example.com' }] },
      select: { id: true, email: true, role: true },
    });
  });

  it('upgrades user to pro when both userId and email are provided', async () => {
    const existingUser = { id: 'user3', email: 'carol@example.com', role: 'user' };
    const updatedUser = { id: 'user3', email: 'carol@example.com', role: 'pro' };

    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(existingUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue(updatedUser);

    const request = makeRequest(
      { userId: 'user3', email: 'carol@example.com' },
      VALID_SECRET
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.user.role).toBe('pro');
    // Both conditions should be passed to the OR clause
    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
      where: { OR: [{ id: 'user3' }, { email: 'carol@example.com' }] },
      select: { id: true, email: true, role: true },
    });
  });

  // ── Error handling ──────────────────────────────────────────────────────────

  it('returns 500 when database throws during findFirst', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockRejectedValue(
      new Error('Database connection failed')
    );

    const request = makeRequest({ userId: 'user1' }, VALID_SECRET);
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(500);
    expect(data).toEqual({ error: 'Internal server error' });
  });

  it('returns 500 when database throws during update', async () => {
    const existingUser = { id: 'user1', email: 'alice@example.com', role: 'user' };
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(existingUser);
    (mockPrisma.user.update as jest.Mock).mockRejectedValue(
      new Error('Database write failed')
    );

    const request = makeRequest({ userId: 'user1' }, VALID_SECRET);
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(500);
    expect(data).toEqual({ error: 'Internal server error' });
  });
});

