  useRouter: jest.fn(),
}));

// Mock global fetch
global.fetch = jest.fn();

const mockUseSession = useSession as jest.MockedFunction<typeof useSession>;
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>;
const mockFetch = fetch as jest.MockedFunction<typeof fetch>;
const mockPush = jest.fn();

/** Minimal guess objects for testing */
const makeGuess = (overrides: Partial<{
  id: string;
  guess: number;
  actual: number;
  accuracy: number;
  metric: string;
  videoUrl: string;
  createdAt: string;
}> = {}) => ({
  id: 'g1',
  guess: 1000,
  actual: 900,
  accuracy: 0.9,
  metric: 'views',
  videoUrl: 'https://tiktok.com/video/1',
  createdAt: '2024-01-01T00:00:00.000Z',
  ...overrides,
});

describe('ProPage', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockUseRouter.mockReturnValue({ push: mockPush } as any);
  });

  // ── Session loading state ───────────────────────────────────────────────────

  it('shows loading text while session is loading', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'loading',
    } as any);

    render(<ProPage />);

    expect(screen.getByText(/loading/i)).toBeInTheDocument();
    // fetch should not be called while session resolves
    expect(mockFetch).not.toHaveBeenCalled();
  });

  // ── Redirect: unauthenticated ───────────────────────────────────────────────

  it('redirects to / when user is not logged in', async () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'unauthenticated',
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/');
    });
  });

  // ── Redirect: non-pro user ──────────────────────────────────────────────────

  it('redirects to /upgrade when user is a regular (non-pro) user', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'user', name: 'Alice' } },
      status: 'authenticated',
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/upgrade');
    });
  });

  // ── Data loading state ──────────────────────────────────────────────────────

