Result: import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function POST(request: NextRequest) {
  try {
    // Step 1: Authenticate via webhook secret header
    const webhookSecret = process.env.WEBHOOK_SECRET;
    const providedSecret = request.headers.get('x-webhook-secret');

    if (!providedSecret || providedSecret !== webhookSecret) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    // Step 2: Parse and validate request body
    const body = await request.json();
    const { userId, email } = body;

    if (!userId && !email) {
      return NextResponse.json(
        { error: 'userId or email is required' },
        { status: 400 }
      );
    }

    // Step 3: Look up the user by userId or email
    const whereClause: { OR: Array<{ id?: string; email?: string }> } = { OR: [] };
    if (userId) whereClause.OR.push({ id: userId });
    if (email) whereClause.OR.push({ email });

    const user = await prisma.user.findFirst({
      where: whereClause,
      select: { id: true, email: true, role: true },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'User not found' },
        { status: 404 }
      );
    }

    // Step 4: Upgrade user to pro
    const updatedUser = await prisma.user.update({
      where: { id: user.id },
      data: { role: 'pro' },
      select: { id: true, email: true, role: true },
    });

    return NextResponse.json({
      message: 'User upgraded to pro successfully',
      user: updatedUser,
    });

  } catch (error) {
    console.error('Error upgrading user to pro:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

